class Admin_Model_Zasilkovna extends Admin_Model_Base_Zasilkovna {

    const ZASILKOVNA_CZ_ID = 13;
    const ZASILKOVNA_SK_ID = 12;
    const ZASILKOVNA_HOUSE_DELIVERY_ID = 2;


    const CHECK_TYPE = [
        'OneSide' => 'MaxOneSideLengthInMM',
        'AllSides' => 'MaxTotalSideLengthInMM'
    ];
    const OPTIONS = [
        self::CHECK_TYPE['OneSide'] => 500,
        self::CHECK_TYPE['AllSides'] => 1200,
    ];

    /**
     * @param int $pickupPlaceID
     * @param string $pickupPlaceName
     * @param string $pickupPlaceAddress
     * @return Admin_Model_Zasilkovna
     */
    public static function assignZasilkovna(int $pickupPlaceID, string $pickupPlaceName, string $pickupPlaceAddress): self {
        $zasilkovna = new Admin_Model_Zasilkovna();
        $zasilkovna->PickupPlace_ID = $pickupPlaceID;
        $zasilkovna->PickupPlaceName = $pickupPlaceName;
        $zasilkovna->PickupPlaceAddress = $pickupPlaceAddress;
        $zasilkovna->save();

        return $zasilkovna;
    }

    /**
     * @param int $productID
     * @return array
     */
    public static function getZasilkovnaDetailsByID(int $ID): array {
