    }

    public static function checkShippingDeliveryConditions(?Cart $cart): bool {
        $valid = false;
        if (!$cart) {
            return false;
        }

        function removeNonNumericChars($value): array|string|null {
            return preg_replace("/[^0-9]/", "", trim($value));
        }

        $cartItems = $cart->getCartItems();

        foreach ($cartItems as $cartItem) {

            $dimensionValues = Admin_Model_ProductionInformation::getSizeSheet($cartItem['product']['ID']);
            if(empty($dimensionValues))
                return false;

            $dimensionValues = explode(',', $dimensionValues);

            foreach ($dimensionValues as $dimensionValue) {
                $itemDimensions = array_map('removeNonNumericChars', explode('x', $dimensionValue));
                $allSidesSum = array_sum($itemDimensions);

                foreach ($itemDimensions as $itemDimension) {
                    if (!self::zasilkovnaDimensionsDeliveryRestriction($itemDimension, self::CHECK_TYPE['OneSide'])) {
                        return false;
                    }
                }
                if (self::zasilkovnaDimensionsDeliveryRestriction($allSidesSum, self::CHECK_TYPE['AllSides'])) {
                    $valid = true;
                } else {
                    return false;
                }
            }
        }

        return $valid;
    }

    private static function zasilkovnaDimensionsDeliveryRestriction($value, $checkType): bool {
        return match ($checkType) {
            self::CHECK_TYPE['OneSide'] => $value <= self::OPTIONS[self::CHECK_TYPE['OneSide']],
            self::CHECK_TYPE['AllSides'] => $value <= self::OPTIONS[self::CHECK_TYPE['AllSides']],
            default => false
        };
    }
}